nodes.signature:
CodeBlock({
  code,
  maxHeight = 220,
  startLine,
  changedLines,
  changedLineKinds,
}: {
  code: string;
  maxHeight?: number | string;
  /** When set, a right-aligned line-number gutter is rendered alongside the code, numbering from
   * this line. Omitted → no gutter (the plain highlighted listing). Highlighting is kept either way. */
  startLine?: number;
  /** Absolute line numbers the diff touched — their gutter numbers go amber (needs the gutter). */
  changedLines?: ReadonlySet<number>;
  /** Per-line change kinds (`added`/`modified`/`deleted`) for colored backgrounds/gutter markers. */
  changedLineKinds?: ReadonlyMap<number, ChangedLineKind>;
})

CodeInlinePanel({
  codeView,
  onExpand,
  onClose,
  showGutter,
}: {
  codeView: CodeView;
  onExpand(): void;
  onClose(): void;
  showGutter?: boolean;
})

ResultRow(props: {
  entry: SymbolEntry;
  active: boolean;
  activeRef?: React.Ref<HTMLButtonElement>;
  onHover: () => void;
  onOpen: () => void;
})

LogicOverlayHeader(props: {
  stack: NodeId[];
  focus: readonly { id: string; label: string }[];
  nodesById: ReadonlyMap<string, GraphNode>;
  onJump: (id: NodeId) => void;
  onFocusJump: (index: number) => void;
  hideGreyed: boolean;
  onToggleHide: () => void;
  ghostDepth: number;
  onSetGhostDepth: (depth: number) => void;
  moreCount: number;
})

LogicBreadcrumb(props: {
  stack: NodeId[];
  focus: readonly { id: string; label: string }[];
  nodesById: ReadonlyMap<string, GraphNode>;
  onJump: (id: NodeId) => void;
  onFocusJump: (index: number) => void;
})

NodeHeader(props: {
  node: GraphNode;
  accent: string;
  entry?: boolean;
  chevron?: "collapsed" | "expanded";
  onToggle?: () => void;
  /** Reserve room at the content's right edge for a card control (the leaf's source button) so
   * the right-aligned kind label never slides under it. */
  reserveRight?: boolean;
  children?: ReactNode;
})
